'use client';

import { useState, useCallback, useEffect } from 'react';
import { predictImage, checkHealth, type PredictionResult } from '@/lib/api';
import ResultPanel  from '@/components/ResultPanel';
import UploadZone   from '@/components/UploadZone';
import Header       from '@/components/Header';
import StatusBar    from '@/components/StatusBar';

export default function Home() {
  const [result,    setResult]    = useState<PredictionResult | null>(null);
  const [loading,   setLoading]   = useState(false);
  const [error,     setError]     = useState<string | null>(null);
  const [apiOnline, setApiOnline] = useState<boolean | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  // Poll backend health every 10 s
  useEffect(() => {
    checkHealth().then(setApiOnline);
    const interval = setInterval(() => checkHealth().then(setApiOnline), 10_000);
    return () => clearInterval(interval);
  }, []);

  const handleFileSelect = useCallback(async (file: File) => {
    setError(null);
    setResult(null);

    const url = URL.createObjectURL(file);
    setPreviewUrl(url);
    setLoading(true);

    try {
      const prediction = await predictImage(file);
      setResult(prediction);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An unexpected error occurred');
    } finally {
      setLoading(false);
    }
  }, []);

  const handleReset = useCallback(() => {
    setResult(null);
    setError(null);
    if (previewUrl) URL.revokeObjectURL(previewUrl);
    setPreviewUrl(null);
  }, [previewUrl]);

  return (
    <div className="min-h-screen grid-bg relative overflow-hidden">
      {/* Ambient glows */}
      <div className="fixed inset-0 pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-cyan-500/[0.03] rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-blue-500/[0.03] rounded-full blur-3xl" />
      </div>

      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <Header />
        <StatusBar apiOnline={apiOnline} />

        <main className="mt-8">
          {!result && !loading && (
            <UploadZone
              onFileSelect={handleFileSelect}
              disabled={apiOnline === false}
              error={error}
            />
          )}
          {loading && previewUrl && <LoadingState previewUrl={previewUrl} />}
          {result && <ResultPanel result={result} onReset={handleReset} />}
        </main>

        <footer className="mt-16 pt-8 border-t border-bg-border">
          <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
            <p className="text-slate-600 text-sm font-mono">
              NeuroScan AI — Research use only. Not a medical device.
            </p>
            <div className="flex items-center gap-4 text-xs text-slate-600 font-mono">
              <span>EfficientNetV2-L</span>
              <span>·</span>
              <span>Grad-CAM</span>
              <span>·</span>
              <span>TensorFlow 2.x</span>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

// ── Defined outside component so useEffect deps are stable ────────────────────
const LOADING_STEPS = [
  'Loading MRI scan…',
  'Preprocessing image (224 × 224)…',
  'Running EfficientNetV2-L inference…',
  'Generating Grad-CAM heatmap…',
  'Computing class probabilities…',
];

function LoadingState({ previewUrl }: { previewUrl: string }) {
  const [currentStep, setCurrentStep] = useState(0);

  useEffect(() => {
    const timers = LOADING_STEPS.map((_, i) =>
      setTimeout(() => setCurrentStep(i), i * 700)
    );
    return () => timers.forEach(clearTimeout);
  }, []); // LOADING_STEPS is module-level const → stable reference, no warning

  return (
    <div className="flex flex-col lg:flex-row gap-8 items-start animate-fade-up">
      {/* Preview with scan line */}
      <div className="flex-1 max-w-md mx-auto lg:mx-0">
        <div className="relative rounded-xl overflow-hidden border border-bg-border glow-cyan">
          <img
            src={previewUrl}
            alt="MRI scan being analyzed"
            className="w-full aspect-square object-cover opacity-60"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-transparent via-cyan-500/5 to-transparent">
            <div className="scan-line" />
          </div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="inline-flex items-center gap-2 bg-bg-base/80 backdrop-blur border border-accent-cyan/30 rounded-full px-4 py-2">
              <div className="w-2 h-2 bg-accent-cyan rounded-full animate-pulse" />
              <span className="text-accent-cyan text-sm font-mono">ANALYZING</span>
            </div>
          </div>
        </div>
      </div>

      {/* Step progress */}
      <div className="flex-1">
        <h3 className="font-display text-xl text-white mb-6">Processing MRI Scan</h3>
        <div className="space-y-3">
          {LOADING_STEPS.map((step, i) => (
            <div
              key={step}
              className={`flex items-center gap-3 transition-all duration-500 ${
                i <= currentStep ? 'opacity-100' : 'opacity-20'
              }`}
            >
              <div
                className={`w-6 h-6 rounded-full border flex items-center justify-center flex-shrink-0 transition-all duration-300 ${
                  i < currentStep
                    ? 'bg-accent-green border-accent-green'
                    : i === currentStep
                    ? 'border-accent-cyan animate-pulse'
                    : 'border-bg-border'
                }`}
              >
                {i < currentStep && (
                  <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                )}
                {i === currentStep && (
                  <div className="w-2 h-2 bg-accent-cyan rounded-full" />
                )}
              </div>
              <span
                className={`font-mono text-sm ${
                  i === currentStep
                    ? 'text-accent-cyan'
                    : i < currentStep
                    ? 'text-slate-400'
                    : 'text-slate-600'
                }`}
              >
                {step}
              </span>
            </div>
          ))}
        </div>

        <div className="mt-8 p-4 rounded-lg border border-bg-border bg-bg-surface">
          <p className="text-xs text-slate-500 font-mono leading-relaxed">
            Model: EfficientNetV2-L &nbsp;|&nbsp; Backbone: ImageNet pretrained<br />
            Input: 224 × 224 &nbsp;|&nbsp; Classes: glioma · meningioma · notumor · pituitary
          </p>
        </div>
      </div>
    </div>
  );
}