'use client';

import { useState } from 'react';
import { type PredictionResult } from '@/lib/api';

interface ResultPanelProps {
  result: PredictionResult;
  onReset: () => void;
}

type ViewMode = 'original' | 'heatmap' | 'overlay';

const CLASS_LABELS: Record<string, string> = {
  glioma: 'Glioma',
  meningioma: 'Meningioma',
  notumor: 'No Tumor',
  pituitary: 'Pituitary',
};

const SEVERITY_CONFIG = {
  none: {
    label: 'CLEAR',
    bg: 'bg-green-500/10',
    border: 'border-green-500/30',
    text: 'text-green-400',
    glow: 'glow-green',
    bar: 'bg-green-500',
  },
  medium: {
    label: 'DETECTED',
    bg: 'bg-orange-500/10',
    border: 'border-orange-500/30',
    text: 'text-orange-400',
    glow: '',
    bar: 'bg-orange-500',
  },
  high: {
    label: 'DETECTED',
    bg: 'bg-red-500/10',
    border: 'border-red-500/30',
    text: 'text-red-400',
    glow: 'glow-red',
    bar: 'bg-red-500',
  },
};

export default function ResultPanel({ result, onReset }: ResultPanelProps) {
  const [viewMode, setViewMode] = useState<ViewMode>('overlay');
  const severity = SEVERITY_CONFIG[result.severity];
  const predLabel = CLASS_LABELS[result.prediction] || result.prediction;

  const currentImage = {
    original: result.original_image,
    heatmap: result.heatmap_image,
    overlay: result.overlay_image,
  }[viewMode];

  return (
    <div className="animate-fade-up space-y-6">
      {/* Top bar */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className={`px-3 py-1.5 rounded-md ${severity.bg} border ${severity.border}`}>
            <span className={`text-xs font-mono font-bold ${severity.text}`}>
              {result.severity === 'none' ? '✓' : '!'} {severity.label}
            </span>
          </div>
          <span className="text-slate-400 font-mono text-sm">Analysis complete</span>
        </div>
        <button
          onClick={onReset}
          className="flex items-center gap-2 px-4 py-2 rounded-lg border border-bg-border text-slate-400 hover:text-white hover:border-accent-cyan/50 transition-all text-sm font-mono"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
              d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
          </svg>
          New Scan
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
        {/* Image viewer */}
        <div className="lg:col-span-3 space-y-3">
          <div className="flex gap-1 p-1 bg-bg-surface rounded-lg border border-bg-border w-fit">
            {(['original', 'heatmap', 'overlay'] as ViewMode[]).map((mode) => (
              <button
                key={mode}
                onClick={() => setViewMode(mode)}
                className={`px-4 py-1.5 rounded-md text-xs font-mono transition-all capitalize ${
                  viewMode === mode ? 'bg-accent-cyan text-bg-base font-medium' : 'text-slate-500 hover:text-slate-300'
                }`}
              >
                {mode}
              </button>
            ))}
          </div>

          <div className={`relative rounded-xl overflow-hidden border border-bg-border aspect-square ${severity.glow}`}>
            <img
              src={`data:image/png;base64,${currentImage}`}
              alt={`${viewMode} MRI`}
              className="w-full h-full object-cover"
            />
            <div className="absolute top-3 left-3">
              <span className="px-2 py-1 bg-bg-base/80 backdrop-blur rounded text-xs font-mono text-slate-400 border border-bg-border">
                {viewMode === 'heatmap' ? 'Grad-CAM' : viewMode === 'overlay' ? 'Overlay' : 'Original'}
              </span>
            </div>
            <div className="absolute bottom-3 right-3">
              <span className={`px-2 py-1 rounded text-xs font-mono font-bold ${severity.bg} ${severity.text} border ${severity.border}`}>
                {predLabel}
              </span>
            </div>
          </div>

          {viewMode === 'heatmap' && (
            <p className="text-xs text-slate-500 font-mono text-center">
              Red regions = highest model attention · Blue regions = lowest attention
            </p>
          )}
        </div>

        {/* Results panel */}
        <div className="lg:col-span-2 space-y-4">
          {/* Primary prediction */}
          <div className={`p-5 rounded-xl border ${severity.border} ${severity.bg}`}>
            <p className="text-xs font-mono text-slate-500 mb-1">PRIMARY DIAGNOSIS</p>
            <h2 className={`font-display text-3xl font-bold ${severity.text} mb-3`}>
              {predLabel}
            </h2>
            <div className="flex items-center gap-2">
              <div className="flex-1 bg-bg-base/50 rounded-full h-2 overflow-hidden">
                <div
                  className={`h-full rounded-full transition-all duration-1000 ${severity.bar}`}
                  style={{ width: `${result.confidence}%` }}
                />
              </div>
              <span className={`text-sm font-mono font-bold ${severity.text} min-w-fit`}>
                {result.confidence.toFixed(1)}%
              </span>
            </div>
          </div>

          {/* Description */}
          <div className="p-4 rounded-xl border border-bg-border bg-bg-surface">
            <p className="text-xs font-mono text-slate-500 mb-2">CLINICAL NOTES</p>
            <p className="text-sm text-slate-300 leading-relaxed">{result.description}</p>
          </div>

          {/* All probabilities */}
          <div className="p-4 rounded-xl border border-bg-border bg-bg-surface">
            <p className="text-xs font-mono text-slate-500 mb-3">CLASS PROBABILITIES</p>
            <div className="space-y-3">
              {[...result.probabilities]
                .sort((a, b) => b.probability - a.probability)
                .map((cls) => {
                  const isPredicted = cls.name === result.prediction;
                  return (
                    <div key={cls.name}>
                      <div className="flex justify-between items-center mb-1">
                        <span className={`text-xs font-mono ${isPredicted ? 'text-white font-medium' : 'text-slate-500'}`}>
                          {CLASS_LABELS[cls.name] || cls.name}
                          {isPredicted && <span className="ml-2 text-accent-cyan">◆</span>}
                        </span>
                        <span className={`text-xs font-mono tabular-nums ${isPredicted ? severity.text : 'text-slate-500'}`}>
                          {cls.percentage.toFixed(2)}%
                        </span>
                      </div>
                      <div className="h-1.5 bg-bg-base rounded-full overflow-hidden">
                        <div
                          className={`h-full rounded-full transition-all duration-700 ${isPredicted ? severity.bar : 'bg-slate-700'}`}
                          style={{ width: `${cls.percentage}%` }}
                        />
                      </div>
                    </div>
                  );
                })}
            </div>
          </div>

          {/* Raw output */}
          <details className="group">
            <summary className="cursor-pointer text-xs font-mono text-slate-600 hover:text-slate-400 transition-colors list-none flex items-center gap-2">
              <svg className="w-3 h-3 transition-transform group-open:rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
              </svg>
              Raw output
            </summary>
            <div className="mt-2 p-3 rounded-lg bg-bg-base border border-bg-border overflow-auto max-h-40">
              <pre className="text-xs font-mono text-slate-500">
{JSON.stringify({
  prediction: result.prediction,
  confidence: result.confidence,
  probabilities: Object.fromEntries(
    result.probabilities.map(p => [p.name, p.percentage.toFixed(4) + '%'])
  )
}, null, 2)}
              </pre>
            </div>
          </details>
        </div>
      </div>

      {/* Disclaimer */}
      <div className="p-4 rounded-lg bg-amber-500/5 border border-amber-500/20 flex items-start gap-3">
        <svg className="w-4 h-4 text-amber-400 flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
            d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L4.082 16.5c-.77.833.192 2.5 1.732 2.5z" />
        </svg>
        <p className="text-xs text-amber-400/80 font-mono leading-relaxed">
          <strong>Medical Disclaimer:</strong> This tool is for research and educational purposes only.
          Results must not be used for clinical diagnosis. Always consult a qualified radiologist or neurologist.
        </p>
      </div>
    </div>
  );
}